import { Injectable, Scope } from '@nestjs/common';
import { Request } from 'express';
import { MemorySaver } from '@langchain/langgraph';
import { ENodeName, TalkableAgents } from '../common/constant';
import { HumanMessage } from '@langchain/core/messages';
import { randomUUID } from 'crypto';
import { dispatchStreamEvent, ToolInputState } from './stream/stream-handlers';
import { EModelName, getModel } from '../config/model';
import { warn } from '../logger';
import createSimpleDeepAgent from './simple-deep-agent';
import { ConversationSandboxManager } from './sandbox/conversation-sandbox.manager';

interface RequestWithLogId extends Request {
  logId?: string;
}

export interface IGraphEvent<T = unknown> {
  id: string;
  event: string;
  timestamp: number;
  node?: ENodeName;
  data?: T;
  subagent_type?: string;
  subagent_namespace?: string;
}

export interface IGraphOptions {
  model: EModelName;
  conversation_id: string;
  signal?: AbortSignal;
  request: RequestWithLogId;
}

function isENodeName(value: string): value is ENodeName {
  return (TalkableAgents as string[]).includes(value);
}

function resolveNode(metadata?: Record<string, unknown>): ENodeName | undefined {
  if (!metadata) {
    return undefined;
  }

  const checkpointNs = metadata.checkpoint_ns as string | undefined;
  if (checkpointNs) {
    for (const part of checkpointNs.split(':')) {
      if (isENodeName(part)) return part as ENodeName;
    }
  }
  const agentName = metadata.lc_agent_name as string | undefined;
  if (agentName && isENodeName(agentName)) return agentName as ENodeName;
  return undefined;
}

@Injectable({ scope: Scope.DEFAULT })
export class AgentsService {
  constructor(private readonly sandboxManager: ConversationSandboxManager) {}

  private saver = new MemorySaver();

  async *run(input: string | unknown | undefined, options: IGraphOptions): AsyncGenerator<IGraphEvent> {
    const graph = await this.createGraph(options.model, options.conversation_id);
    const graphInput = (typeof input === 'string' ? { messages: [new HumanMessage(input)] } : input ?? null) 
    const stream = graph.streamEvents(
      graphInput,
      {
        version: 'v2' as const,
        signal: options.signal,
        maxConcurrency:4,
        configurable: { thread_id: options.conversation_id },
        ...{
          metadata: { logid: options.request.logId || randomUUID() },
        }
      } ,
    );

    const toolState: ToolInputState = { inputtingTool: undefined, subagentNamespaces: {} };
    for await (const streamEvent of stream) {
      if (!streamEvent || typeof streamEvent !== 'object' || ArrayBuffer.isView(streamEvent)) {
        warn({ streamEventType: typeof streamEvent }, 'Unexpected non-object stream event');
        continue;
      }

      const { run_id, name, event, data, metadata } = streamEvent as {
        run_id: string;
        name: string;
        event: string;
        data: unknown;
        metadata?: Record<string, unknown>;
      };


      const node = resolveNode(metadata);
      const graphEvent = dispatchStreamEvent(
        event,
        { run_id, name, data: data as Record<string, unknown>, node, metadata },
        toolState,
      );
      if (graphEvent) yield graphEvent;
    }
  }

  private createGraph(model: EModelName, conversationId: string) {
    return createSimpleDeepAgent(getModel(model), conversationId, this.sandboxManager);
  }
}

